// Formats clarification questions to present to the user
const input = $input.first().json;
const questions = input.query || input.questions || input.input || 'more information';

return {
  json: {
    clarificationNeeded: true,
    message: `Before I generate this post, I need a few more details:\n\n${questions}\n\nOnce you provide these I'll create the post right away!`
  }
};

// Parse raw JSON output from AI Agent, then build YAML frontmatter + template
const rawOutput = $input.all()[0].json.output;
let json;

if (typeof rawOutput === 'string') {
  try {
    json = JSON.parse(rawOutput.trim());
  } catch (e) {
    // LLM sometimes adds fluff around the JSON — extract the object
    const match = rawOutput.match(/\{[\s\S]*\}/);
    if (!match) {
      throw new Error(`AI output contained no JSON object.\nReceived: ${rawOutput.substring(0, 300)}`);
    }
    try {
      json = JSON.parse(match[0]);
    } catch (e2) {
      throw new Error(`AI output was not valid JSON: ${e2.message}\nReceived: ${rawOutput.substring(0, 300)}`);
    }
  }
} else if (rawOutput && typeof rawOutput === 'object') {
  json = rawOutput;
} else {
  throw new Error('No output received from AI Agent');
}

// Convert arrays to space-separated strings for YAML frontmatter
const mentionsString = Array.isArray(json.mentions) ? json.mentions.join(' ') : json.mentions || '';
const hashtagsString = Array.isArray(json.hashtags) ? json.hashtags.join(' ') : json.hashtags || '';

const yaml = `---
title: "${json.title}"
type: content
status: draft
platform: ${json.platform}
band-name: "${json.bandName}"
band-username-ig: "${json.bandInstagram}"
publish-date: "${json.postDate}"
record-date: "${json.recordDate || ''}"
caption: "${json.caption}"
hashtags: "${hashtagsString}"
mentions: "${mentionsString}"
yt-description: |
${(json.ytDescription || '').split('\n').map(l => '  ' + l).join('\n')}
yt-tags: "${json.ytTags || ''}"
yt-playlist: "${json.ytPlaylist || ''}"
media-link: "${json.mediaLink || ''}"
media-type: ${json.mediaType || 'Video'}
privacy-status: unlisted
ai-generated: true
ai-generated-date: ${new Date().toISOString().split('T')[0]}
created-date: ${new Date().toISOString().split('T')[0]}
---

# YouTube Post Draft

*Auto-populated: ${new Date().toLocaleString()}*

## Title (Video Title)

<% tp.frontmatter["caption"] %>

---

## Description (Video Description)

> Status: <% tp.frontmatter["status"] %>
> Platform: <% tp.frontmatter["platform"] %>
> AI Generated: <% tp.frontmatter["ai-generated"] %>

Your full description goes here...

